import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)
print('=== Comparison ===')
changes = False
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(k, 'MISSING')
    av = a.get(k, 'MISSING')
    status = 'CHANGED' if bv != av else 'OK'
    if status == 'CHANGED': changes = True
    print(f'{k[0]:15s} {k[1]:50s} {bv:>10s} -> {av:>10s}  [{status}]')
if not changes:
